// ═══════════════════════════════════════════════════════════════
// SPIKE HUNTER PRO v13 — IMPROVED BREAKOUT DETECTION
// Layer 1: Freshness | Layer 2: Dedup | Layer 3: 4H Trend | Layer 4: Enhanced Breakout
// ═══════════════════════════════════════════════════════════════

const webhookData = $('Webhook Trigger').first().json.body;
const symbol = webhookData.symbol;
const wsPctChange = parseFloat(webhookData.priceChangePercent);
const wsDirection = webhookData.direction;
const dynamicThreshold = webhookData.threshold ? parseFloat(webhookData.threshold) : 3.0;
const nowTs = Date.now();

// LAYER 1: FRESHNESS CHECK
const FRESHNESS_LIMIT_MS = 3 * 60 * 1000;
if (webhookData.triggeredAt) {
  const triggeredTs = new Date(webhookData.triggeredAt).getTime();
  const ageSec = Math.round((nowTs - triggeredTs) / 1000);
  if (nowTs - triggeredTs > FRESHNESS_LIMIT_MS) {
    return [{ json: { isHot: false, symbol, rejectReason: '\u23f0 STALE: Signal sudah ' + ageSec + 's (maks 180s). Dilewati.' } }];
  }
}

// LAYER 2: Dedup state
const DEDUP_WINDOW_MS = 2 * 60 * 60 * 1000;
const SCORE_UPGRADE_THRESHOLD = 10;
const state = $getWorkflowStaticData('global');
if (!state.signalCache) state.signalCache = {};
for (const key of Object.keys(state.signalCache)) {
  if (nowTs - state.signalCache[key].ts > 4 * 60 * 60 * 1000) delete state.signalCache[key];
}
const dedupKey = symbol + '_' + wsDirection;
const lastEntry = state.signalCache[dedupKey];

// KLINES PARSING
function parseKlines(nodeName) {
  let raw = $(nodeName).first().json;
  let data = Array.isArray(raw) ? raw : (typeof raw.data === 'string' ? JSON.parse(raw.data) : raw.data);
  if (!Array.isArray(data) || data.length < 20) return null;
  return {
    open:   data.map(function(k) { return parseFloat(k[1]); }),
    high:   data.map(function(k) { return parseFloat(k[2]); }),
    low:    data.map(function(k) { return parseFloat(k[3]); }),
    close:  data.map(function(k) { return parseFloat(k[4]); }),
    volume: data.map(function(k) { return parseFloat(k[5]); }),
  };
}

const tf1h = parseKlines('Get Klines 1h');
const tf4h = parseKlines('Get Klines 4h');
if (!tf1h) return [{ json: { isHot: false, symbol, rejectReason: 'Data klines 1H tidak cukup' } }];

// INDICATOR FUNCTIONS
function calcEMA(p, n) {
  const k = 2/(n+1); let e = p.slice(0,n).reduce(function(a,b){return a+b;})/n;
  const r = new Array(n-1).fill(null); r.push(e);
  for (let i=n; i<p.length; i++) { e=(p[i]-e)*k+e; r.push(e); }
  return r;
}
function calcRSI(p, n) {
  n = n || 14;
  if (p.length < n+1) return 50;
  let g=0,lo=0;
  for (let i=1; i<=n; i++) { let d=p[i]-p[i-1]; d>=0?g+=d:lo-=d; }
  let ag=g/n, al=lo/n;
  for (let i=n+1; i<p.length; i++) {
    let d=p[i]-p[i-1]; ag=((ag*(n-1))+(d>=0?d:0))/n; al=((al*(n-1))+(d<0?-d:0))/n;
  }
  return al===0 ? 100 : 100-(100/(1+(ag/al)));
}
function calcMACD(p) {
  const f=calcEMA(p,12), s=calcEMA(p,26), ml=[];
  for (let i=0; i<p.length; i++) if(f[i]!==null&&s[i]!==null) ml.push(f[i]-s[i]);
  if (ml.length<9) return {h:0,ph:0,cu:false,cd:false,hist:0};
  const sl=calcEMA(ml,9);
  const lm=ml[ml.length-1],ls=sl[sl.length-1]||0,pm=ml[ml.length-2]||lm,ps=sl[sl.length-2]||ls;
  return {h:lm-ls, ph:pm-ps, cu:pm<=ps&&lm>ls, cd:pm>=ps&&lm<ls, hist:lm-ls};
}
function calcATR(h,l,c,n) {
  n=n||14; if(h.length<n+1) return 0;
  let t=[h[0]-l[0]];
  for(let i=1;i<h.length;i++) t.push(Math.max(h[i]-l[i],Math.abs(h[i]-c[i-1]),Math.abs(l[i]-c[i-1])));
  let a=t.slice(0,n).reduce(function(x,y){return x+y;})/n;
  for(let i=n;i<t.length;i++) a=(a*(n-1)+t[i])/n;
  return a;
}
function calcADX(h,l,c,n) {
  n=n||14; if(h.length<n*3) return 0;
  let t=[],pd=[],md=[];
  for(let i=1;i<h.length;i++) {
    t.push(Math.max(h[i]-l[i],Math.abs(h[i]-c[i-1]),Math.abs(l[i]-c[i-1])));
    let u=h[i]-h[i-1],d=l[i-1]-l[i];
    pd.push(u>d&&u>0?u:0); md.push(d>u&&d>0?d:0);
  }
  let aT=t.slice(0,n).reduce(function(a,b){return a+b;}),aP=pd.slice(0,n).reduce(function(a,b){return a+b;}),aM=md.slice(0,n).reduce(function(a,b){return a+b;});
  const dx=[];
  for(let i=n;i<t.length;i++) {
    aT=aT-aT/n+t[i]; aP=aP-aP/n+pd[i]; aM=aM-aM/n+md[i];
    let pI=(aP/aT)*100,mI=(aM/aT)*100;
    dx.push((pI+mI)===0?0:Math.abs(pI-mI)/(pI+mI)*100);
  }
  if(dx.length<n) return 0;
  let a=dx.slice(0,n).reduce(function(x,y){return x+y;})/n;
  for(let i=n;i<dx.length;i++) a=((a*(n-1))+dx[i])/n;
  return a;
}

// 4H TREND ANALYSIS
let trend4h = 'SIDEWAYS';
let rsi4h = 50;
let trend4hBias = 'NEUTRAL';
let res4h = 0;
if (tf4h) {
  const c4 = tf4h.close, h4 = tf4h.high;
  const e21_4h = calcEMA(c4, 21);
  const e50_4h = calcEMA(c4, 50);
  const price4h = c4[c4.length - 1];
  const E21_4h = e21_4h[e21_4h.length-1] || price4h;
  const E50_4h = e50_4h[e50_4h.length-1] || price4h;
  rsi4h = calcRSI(c4);
  res4h = Math.max.apply(null, h4.slice(-20));
  if (price4h > E21_4h && E21_4h > E50_4h) { trend4h = 'UPTREND'; trend4hBias = 'BULLISH'; }
  else if (price4h < E21_4h && E21_4h < E50_4h) { trend4h = 'DOWNTREND'; trend4hBias = 'BEARISH'; }
}

// 1H INDICATORS
const c = tf1h.close, h = tf1h.high, l = tf1h.low, o = tf1h.open, v = tf1h.volume;
const price = c[c.length - 1];
const idx = c.length - 1;
const _rsi = calcRSI(c);
const _prevRsi = calcRSI(c.slice(0, -1));
const _macd = calcMACD(c);
const _atr = calcATR(h, l, c);
const _adx = calcADX(h, l, c);
const e21 = calcEMA(c, 21), e50 = calcEMA(c, 50);
const E21 = e21[e21.length-1]||price, E50 = e50[e50.length-1]||price;
const avgVol = v.slice(-20).reduce(function(a,b){return a+b;})/20;
const volRatio = v[v.length-1]/avgVol;
const res1h = Math.max.apply(null, h.slice(-50));
const recentL = Math.min.apply(null, l.slice(-50));
// Multi-TF effective resistance
const effectiveRes = (res4h > 0 && Math.abs(res4h - res1h) / price < 0.05)
  ? Math.max(res4h, res1h) : (res4h > 0 ? Math.min(res4h, res1h) : res1h);
let trend = 'SIDEWAYS';
if(price>E21&&E21>E50) trend = 'UPTREND';
else if(price<E21&&E21<E50) trend = 'DOWNTREND';
const body = Math.abs(c[idx] - o[idx]);
const range = h[idx] - l[idx];
const upperWick = h[idx] - Math.max(c[idx], o[idx]);

let score = 0, signal = 'NEUTRAL', strategy = 'WAIT', confidence = 'LOW';
const reasons = [];

// STRATEGY 1: BUY THE DIP (LONG)
if (wsPctChange <= -dynamicThreshold) {
  if (_rsi >= 40) { reasons.push('RSI ' + _rsi.toFixed(0) + ' tidak oversold'); }
  else {
    let ff = 0;
    for (let k = idx-5; k <= idx; k++) {
      if (k > 24) { const ll = Math.min.apply(null, l.slice(k-24, k)); if (l[k] < ll) ff++; }
    }
    if (ff >= 3) { reasons.push('FREEFALL - skip'); }
    else if (E21 <= price * 1.003) { reasons.push('EMA21 tidak di atas harga'); }
    else if (c[idx] <= o[idx]) { reasons.push('Candle merah'); }
    else if (_rsi <= _prevRsi) { reasons.push('RSI masih turun'); }
    else {
      if (_rsi < 22) { score += 20; reasons.push('RSI ' + _rsi.toFixed(0) + ' extreme'); }
      else if (_rsi < 28) { score += 15; reasons.push('RSI ' + _rsi.toFixed(0) + ' oversold'); }
      else if (_rsi < 33) { score += 10; reasons.push('RSI ' + _rsi.toFixed(0)); }
      else { score += 5; }
      const absPct = Math.abs(wsPctChange);
      if (absPct >= Math.max(8, dynamicThreshold*2)) { score += 12; reasons.push(absPct.toFixed(0) + '% crash'); }
      else if (absPct >= Math.max(5, dynamicThreshold*1.5)) { score += 9; reasons.push(absPct.toFixed(0) + '% drop'); }
      else { score += 6; }
      if (range > 0 && body/range > 0.4) { score += 15; reasons.push('Bullish candle'); } else { score += 8; reasons.push('Green candle'); }
      if (_macd.cu) { score += 10; reasons.push('MACD Cross Up'); }
      else if (_macd.h < 0 && _macd.h > _macd.ph) { score += 6; reasons.push('MACD turning'); }
      if (volRatio > 3.0) { score += 8; reasons.push('Vol ' + volRatio.toFixed(1) + 'x'); }
      else if (volRatio > 2.0) { score += 5; reasons.push('Vol ' + volRatio.toFixed(1) + 'x'); }
      const sup3d = Math.min.apply(null, l.slice(Math.max(0, idx-72), idx));
      const dSup = (price - sup3d) / price * 100;
      if (dSup < 0.5) { score += 10; reasons.push('Double bottom'); }
      else if (dSup < 1.5) { score += 6; reasons.push('Near support'); }
      else if (dSup < 3) { score += 3; }
      if (range > 0 && (Math.min(c[idx],o[idx])-l[idx])/range > 0.5) { score += 5; reasons.push('Wick up'); }
      if (_adx < 20) { score += 5; reasons.push('ADX weak'); } else if (_adx > 35) { score -= 3; }
      if (trend4hBias === 'BULLISH') { score += 8; reasons.push('4H UPTREND \u2705'); }
      else if (trend4hBias === 'BEARISH') { score -= 10; reasons.push('4H DOWNTREND \u26a0\ufe0f'); }
      if (score >= 55) { signal = 'STRONG BUY'; strategy = 'LONG (Buy Dip)'; confidence = 'VERY HIGH'; }
      else if (score >= 45) { signal = 'BUY'; strategy = 'LONG (Buy Dip)'; confidence = 'HIGH'; }
      else if (score >= 40) { signal = 'POSSIBLE LONG'; strategy = 'LONG (Buy Dip)'; confidence = 'MEDIUM'; }
    }
  }
}
// STRATEGY 2 & 3: PUMP SCENARIOS
else if (wsPctChange >= dynamicThreshold) {
  let shortScore = 0, breakoutScore = 0;
  const shortReasons = [], breakoutReasons = [];

  // SHORT: Overbought Mean Reversion
  if (_rsi >= 75) { shortScore += 20; shortReasons.push('RSI Extreme OB (' + _rsi.toFixed(0) + ')'); }
  else if (_rsi >= 70) { shortScore += 15; shortReasons.push('RSI Overbought (' + _rsi.toFixed(0) + ')'); }
  else if (_rsi >= 65) { shortScore += 5; shortReasons.push('RSI High (' + _rsi.toFixed(0) + ')'); }
  if (wsPctChange >= Math.max(10, dynamicThreshold*2)) { shortScore += 15; shortReasons.push('Massive Pump (' + wsPctChange.toFixed(0) + '%)'); }
  else if (wsPctChange >= Math.max(7, dynamicThreshold*1.5)) { shortScore += 10; shortReasons.push('Big Pump (' + wsPctChange.toFixed(0) + '%)'); }
  if (c[idx] < o[idx]) { shortScore += 15; shortReasons.push('Red Reversal Candle'); }
  if (range > 0 && upperWick/range > 0.4) { shortScore += 10; shortReasons.push('Long Upper Wick'); }
  if (_macd.cd) { shortScore += 10; shortReasons.push('MACD Bearish Cross'); }
  else if (_macd.h > 0 && _macd.h < _macd.ph) { shortScore += 5; shortReasons.push('MACD Bull Fading'); }
  const dResShort = (effectiveRes - price) / price * 100;
  if (dResShort > -0.5 && dResShort < 1.0) { shortScore += 10; shortReasons.push('Near MTF Resistance'); }
  if (trend4hBias === 'BEARISH') { shortScore += 8; shortReasons.push('4H DOWNTREND \u2705'); }
  else if (trend4hBias === 'BULLISH') { shortScore -= 10; shortReasons.push('4H UPTREND \u26a0\ufe0f'); }

  // BREAKOUT LONG (Enhanced v13)
  // 1. RSI momentum zone
  if (_rsi >= 55 && _rsi < 70) { breakoutScore += 15; breakoutReasons.push('RSI Momentum (' + _rsi.toFixed(0) + ')'); }

  // 2. Volume vs last 5 bars (breakout volume confirmation)
  const vol5avg = v.slice(idx-5, idx).reduce(function(a,b){return a+b;}, 0) / 5;
  const volBreakRatio = v[idx] / vol5avg;
  if (volBreakRatio > 3.0) { breakoutScore += 20; breakoutReasons.push('\ud83d\udd25 Vol Breakout ' + volBreakRatio.toFixed(1) + 'x (5bar avg)'); }
  else if (volBreakRatio > 2.0) { breakoutScore += 14; breakoutReasons.push('Vol Breakout ' + volBreakRatio.toFixed(1) + 'x'); }
  else if (volBreakRatio > 1.5) { breakoutScore += 8; breakoutReasons.push('Vol Rising ' + volBreakRatio.toFixed(1) + 'x'); }
  else { breakoutReasons.push('Vol lemah ' + volBreakRatio.toFixed(1) + 'x — potensi fakeout'); }

  // 3. Candle body quality (Marubozu = bersih, no wick = confidence)
  if (c[idx] > o[idx] && range > 0) {
    const bodyRatio = body / range;
    if (bodyRatio > 0.75) { breakoutScore += 15; breakoutReasons.push('Strong Marubozu (' + (bodyRatio*100).toFixed(0) + '% body)'); }
    else if (bodyRatio > 0.55) { breakoutScore += 8; breakoutReasons.push('Bullish candle (' + (bodyRatio*100).toFixed(0) + '% body)'); }
    else if (bodyRatio < 0.3) { breakoutScore -= 8; breakoutReasons.push('\u26a0\ufe0f Candle kecil — fakeout risk'); }
  }

  // 4. FAKEOUT FILTER: upper wick panjang = rejection di resistance
  if (range > 0) {
    const wickRatio = upperWick / range;
    if (wickRatio > 0.5) { breakoutScore -= 15; breakoutReasons.push('\ud83d\udea8 Fakeout Warning: Upper wick ' + (wickRatio*100).toFixed(0) + '% — kemungkinan rejection'); }
    else if (wickRatio > 0.35) { breakoutScore -= 8; breakoutReasons.push('\u26a0\ufe0f Upper wick besar ' + (wickRatio*100).toFixed(0) + '%'); }
    else if (wickRatio < 0.15) { breakoutScore += 5; breakoutReasons.push('Clean breakout candle (wick minimal)'); }
  }

  // 5. Multi-TF resistance breakout
  const dRes1h = (price - res1h) / price * 100;
  const dRes4h = res4h > 0 ? (price - res4h) / price * 100 : null;
  if (dRes1h > 0 && dRes1h < 2.0) { breakoutScore += 12; breakoutReasons.push('Breakout Res 1H (+' + dRes1h.toFixed(2) + '%)'); }
  if (dRes4h !== null && dRes4h > 0 && dRes4h < 3.0) { breakoutScore += 18; breakoutReasons.push('\ud83d\udd11 Breakout Res 4H (+' + dRes4h.toFixed(2) + '%) KEY LEVEL'); }
  else if (dRes4h !== null && dRes4h > -1.0 && dRes4h <= 0) { breakoutScore += 8; breakoutReasons.push('Approaching 4H Res (' + Math.abs(dRes4h).toFixed(2) + '% away)'); }

  // 6. MACD momentum
  if (_macd.cu) { breakoutScore += 10; breakoutReasons.push('MACD Bull Cross'); }
  else if (_macd.h > 0 && _macd.h > _macd.ph) { breakoutScore += 7; breakoutReasons.push('MACD Bull Momentum Increasing'); }

  // 7. ADX — breakout butuh tenaga
  if (_adx > 25) { breakoutScore += 8; breakoutReasons.push('ADX Strong (' + _adx.toFixed(0) + ')'); }
  else if (_adx < 15) { breakoutScore -= 5; breakoutReasons.push('ADX Lemah (' + _adx.toFixed(0) + ')'); }

  // 8. 4H Bias
  if (trend4hBias === 'BULLISH') { breakoutScore += 10; breakoutReasons.push('4H UPTREND \u2705 aligned'); }
  else if (trend4hBias === 'BEARISH') { breakoutScore -= 12; breakoutReasons.push('4H DOWNTREND \u26a0\ufe0f counter-trend'); }

  // DECIDE WINNER
  if (shortScore >= 55 && shortScore > breakoutScore) {
    score = shortScore; signal = 'STRONG SELL'; strategy = 'SHORT (Overbought)'; confidence = 'VERY HIGH';
    reasons.push.apply(reasons, shortReasons);
  } else if (shortScore >= 45 && shortScore > breakoutScore) {
    score = shortScore; signal = 'SELL'; strategy = 'SHORT (Overbought)'; confidence = 'HIGH';
    reasons.push.apply(reasons, shortReasons);
  } else if (breakoutScore >= 55) {
    score = breakoutScore; signal = 'STRONG BUY'; strategy = 'LONG (Breakout)'; confidence = 'VERY HIGH';
    reasons.push.apply(reasons, breakoutReasons);
  } else if (breakoutScore >= 45) {
    score = breakoutScore; signal = 'BUY'; strategy = 'LONG (Breakout)'; confidence = 'HIGH';
    reasons.push.apply(reasons, breakoutReasons);
  } else {
    reasons.push('Pump ' + wsPctChange.toFixed(1) + '% — ShortScore: ' + shortScore + ', BreakoutScore: ' + breakoutScore + ' (min 45)');
  }
  var volBreakRatioVal = volBreakRatio;
} else {
  reasons.push('Change ' + wsPctChange.toFixed(1) + '% masih di bawah threshold ' + dynamicThreshold + '%');
  var volBreakRatioVal = null;
}

let sl = 0, tp1 = 0, tp2 = 0, tp3 = 0, riskPct = '0';
if (_atr > 0) {
  if (strategy.indexOf('LONG') !== -1) {
    sl = price - (_atr * 2.0);
    const slDist = price - sl;
    const meanDist = Math.max(E21 - price, 0);
    tp1 = price + Math.max(meanDist * 0.4, slDist * 1.5);
    tp2 = price + Math.max(meanDist * 0.7, slDist * 2.0);
    tp3 = price + Math.max(meanDist * 1.0, slDist * 3.0);
    riskPct = ((slDist / price) * 100).toFixed(2);
  } else if (strategy.indexOf('SHORT') !== -1) {
    sl = price + (_atr * 2.0);
    const slDist = sl - price;
    const meanDist = Math.max(price - E21, 0);
    tp1 = price - Math.max(meanDist * 0.4, slDist * 1.5);
    tp2 = price - Math.max(meanDist * 0.7, slDist * 2.0);
    tp3 = price - Math.max(meanDist * 1.0, slDist * 3.0);
    riskPct = ((slDist / price) * 100).toFixed(2);
  }
}

const isStrongSignal = signal === 'STRONG BUY' || signal === 'STRONG SELL';

// LAYER 2 CHECK: Deduplication
if (isStrongSignal && lastEntry && (nowTs - lastEntry.ts < DEDUP_WINDOW_MS)) {
  const scoreDiff = score - lastEntry.score;
  const elapsedMin = Math.round((nowTs - lastEntry.ts) / 60000);
  if (scoreDiff < SCORE_UPGRADE_THRESHOLD) {
    return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udd01 DUPLICATE: ' + wsDirection + ' ' + symbol + ' sudah dikirim ' + elapsedMin + 'm lalu (score ' + lastEntry.score + '). Score baru ' + score + ' belum naik cukup.' } }];
  }
}
if (isStrongSignal) { state.signalCache[dedupKey] = { ts: nowTs, score, signal }; }

return [{
  json: {
    symbol, price: price.toFixed(4),
    wsChange: wsPctChange.toFixed(2) + '%', wsDirection,
    signal, strategy, confidence, score,
    reasons: reasons.join(' | '),
    trend1h: trend, trend4h, rsi1h: _rsi.toFixed(1), rsi4h: rsi4h.toFixed(1),
    macdHist: _macd.hist.toFixed(6),
    macdCross: _macd.cu ? 'BULL CROSS' : (_macd.cd ? 'BEAR CROSS' : 'None'),
    adx1h: _adx.toFixed(1), volRatio: volRatio.toFixed(1) + 'x',
    volBreakRatio: volBreakRatioVal ? volBreakRatioVal.toFixed(1) + 'x vs 5bar' : 'N/A',
    ema21: E21.toFixed(4),
    res1h: res1h.toFixed(4), res4h: res4h > 0 ? res4h.toFixed(4) : 'N/A',
    support: recentL.toFixed(4), resistance: effectiveRes.toFixed(4),
    distSupport: ((price - recentL) / price * 100).toFixed(2) + '%',
    distResistance: ((effectiveRes - price) / price * 100).toFixed(2) + '%',
    sl: sl.toFixed(4), tp1: tp1.toFixed(4), tp2: tp2.toFixed(4), tp3: tp3.toFixed(4),
    riskPct: riskPct + '%', atr: _atr.toFixed(6),
    isHot: isStrongSignal,
    rejectReason: !isStrongSignal ? 'Score ' + score + ' (Min 55 for STRONG). ' + reasons.join(', ') : '',
  }
}];
